  ('diplomatic-20fe77d5-moex-00305', 'diplomatic-20fe77d5', 'diplomatic-20fe77d5-moex-112-7f4830a9', 'sub-diplomatic-20fe77d5-03', NULL, 'single_choice', '有關1904年「日俄戰爭」爆發，下列敘述何者正確？', '["導火線係「庚子拳亂」發生，沙俄藉口保護「中東鐵路」佔領中國東北", "經英國調停，日俄於英國訂立《樸資茅斯（Portsmouth）條約》", "日俄議和，俄國將堪察加半島南部割讓給日本", "光緒31年（1905年）簽訂中日《東三省事宜條約》，中國收回俄國在東北的利權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:35+00:00", "source_pdf_sha1": "cb69610e8100", "answer_pdf_sha1": "f2cb8661297c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "101", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-韓文組"}'::jsonb, NULL),
  ('diplomatic-20fe77d5-moex-00306', 'diplomatic-20fe77d5', 'diplomatic-20fe77d5-moex-112-7f4830a9', 'sub-diplomatic-20fe77d5-03', NULL, 'single_choice', '清朝簽訂的對外條約當中，那一個賠款最多？', '["伊犁條約", "辛丑條約", "馬關條約", "天津條約"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:35+00:00", "source_pdf_sha1": "cb69610e8100", "answer_pdf_sha1": "f2cb8661297c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "101", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-韓文組"}'::jsonb, NULL),
  ('diplomatic-20fe77d5-moex-00307', 'diplomatic-20fe77d5', 'diplomatic-20fe77d5-moex-112-7f4830a9', 'sub-diplomatic-20fe77d5-03', NULL, 'single_choice', '有關清朝末年邊疆爭端的敘述，下列何者正確？', '["咸豐6年（1856年），回變最早起於雲南，其得到沙俄的外交支持，並以馬如龍、杜文秀勢力 最大", "咸豐8年（1858年），第一次英法聯軍進逼天津，沙俄將領莫拉維也夫（NikolayN.Muravyov） 乘機出兵璦琿，威逼李鴻章，簽訂《璦琿條約》", "同治3年（1864年）新疆回變，中亞浩罕國國王派部將阿古柏（MuhammadYaqubBek）東來， 建立回教汗國，最後由曾國藩西征討平", "新疆回變發生，沙俄軍隊於同治10年（1871年）佔據伊犂。清廷派遣駐英法大臣曾紀澤前往 聖彼得堡談判，始得爭回部分領土權益"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:35+00:00", "source_pdf_sha1": "cb69610e8100", "answer_pdf_sha1": "f2cb8661297c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "101", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-韓文組"}'::jsonb, NULL),
  ('diplomatic-20fe77d5-moex-00308', 'diplomatic-20fe77d5', 'diplomatic-20fe77d5-moex-112-7f4830a9', 'sub-diplomatic-20fe77d5-03', NULL, 'single_choice', '1899年美國國務卿海約翰（JohnHay）主張中國門戶開放政策，下列敘述何者錯誤？', '["美國在美西戰爭獲勝取得菲律賓後實力增強", "美國在中國商業利益逐漸增多", "美國主張各國門戶開放原是外交傳統", "美國以尊重列強在中國勢力範圍取得的特權爭取支持"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:35+00:00", "source_pdf_sha1": "cb69610e8100", "answer_pdf_sha1": "f2cb8661297c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "101", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-韓文組"}'::jsonb, NULL),
  ('diplomatic-20fe77d5-moex-00309', 'diplomatic-20fe77d5', 'diplomatic-20fe77d5-moex-112-7f4830a9', 'sub-diplomatic-20fe77d5-03', NULL, 'single_choice', '有關於第二次世界大戰期間，同盟國之間的合作，下列敘述何者正確？', '["民國26年（1937年）「七七事變」爆發，美、英為加強對華友誼，迅即撤銷不平等條約", "民國32年（1943年）11月，美國總統羅斯福（FranklinD.Roosevelt）、英國首相邱吉爾（Winston Churchill），邀請國民政府主席蔣中正前往開羅，並發表《開羅宣言》，同意戰後朝鮮獨立", "民國 33 年（1944 年）10 月，中華民國與美、英、法共同宣布《聯合國組織案》，成為「聯合 國」的創始會員國", "民國34年（1945年），希特勒（AdolfHitler）敗亡前，中、美、英3國發表《波茨坦宣言》，要 求德國無條件投降"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:35+00:00", "source_pdf_sha1": "cb69610e8100", "answer_pdf_sha1": "f2cb8661297c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "101", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-韓文組"}'::jsonb, NULL),
  ('diplomatic-20fe77d5-moex-00310', 'diplomatic-20fe77d5', 'diplomatic-20fe77d5-moex-112-7f4830a9', 'sub-diplomatic-20fe77d5-03', NULL, 'single_choice', '有關於美蘇冷戰在二戰結束後的發展，下列敘述何者正確？', '["美國總統杜魯門（HarryS.Truman）1946年3月5日在美國的演講中，率先使用「鐵幕」（Iron Curtain）一詞", "馬歇爾計劃（TheMarshallPlan）在1947年7月啟動，其援助範圍包括現今整個歐盟地區", "圍堵（Containment）政策係由肯楠（GeorgeF.Kennan）所建議，得到美國總統杜魯門的支持", "圍堵（Containment）政策下所組成的集體防衛機制中，目前繼續存在的有「東南亞公約組織」 （SEATO）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:35+00:00", "source_pdf_sha1": "cb69610e8100", "answer_pdf_sha1": "f2cb8661297c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "101", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-韓文組"}'::jsonb, NULL),
  ('diplomatic-20fe77d5-moex-00311', 'diplomatic-20fe77d5', 'diplomatic-20fe77d5-moex-112-7f4830a9', 'sub-diplomatic-20fe77d5-03', NULL, 'single_choice', '第一次世界大戰爆發的原因，下列敘述何者錯誤？', '["德國首相俾斯麥打造的同盟體系失控，因而導致戰爭", "德俄再保條約因俄國不願續約，德俄關係進一步惡化", "德國遂行「大海軍計畫」侵犯英國重大利益", "法俄同盟、英法協商、英俄協商接連實現，使德國面臨外交孤立"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:35+00:00", "source_pdf_sha1": "cb69610e8100", "answer_pdf_sha1": "f2cb8661297c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "101", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-韓文組"}'::jsonb, NULL),
  ('diplomatic-20fe77d5-moex-00312', 'diplomatic-20fe77d5', 'diplomatic-20fe77d5-moex-112-49b2c997', 'sub-diplomatic-20fe77d5-07', NULL, 'essay', '英譯中：（15分）
The first element which differentiates human from animal existence is a
negative one: the relative absence in man of instinctive regulation in the
processofadaptationtothesurroundingworld.Themodeofadaptationofthe
animal to its world remains the same throughout. If its instinctive equipment
isno longerfitto copesuccessfullywith achanging environment,thespecies
will become extinct. The animal can adapt itself to changing conditions by
changing itself. In this fashion, it lives harmoniously, not in the sense of
absence of struggle but in the sense that its inherited equipment makes it a
fixedand unchanging partof itsworld;iteither fitsin or diesout.', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:35+00:00", "source_pdf_sha1": "742ae5e5c67c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "101", "s": "0201", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "外國文(含新聞書信撰寫與編譯)(英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-韓文組"}'::jsonb, NULL),
  ('diplomatic-20fe77d5-moex-00313', 'diplomatic-20fe77d5', 'diplomatic-20fe77d5-moex-112-49b2c997', 'sub-diplomatic-20fe77d5-07', NULL, 'essay', '中譯英：（15分）
左右經營決策的準則無法簡化成一個簡單的公式。傳統上，經濟學
家都主張企業的目標是追求最大利潤。可是，這個簡單的主張本身有幾
點疑慮。首先，就運作面而言，「利潤」這個概念本身是不清楚的，今天
的獲利有可能是以刪減維護費用、拖延投資、剝削員工換來的，也就是
以往後數年的獲利為代價。其次，如果管理高層主張獲利至上，可能會
在企業價值方面對員工傳遞出負面訊息。', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:35+00:00", "source_pdf_sha1": "742ae5e5c67c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "101", "s": "0201", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "外國文(含新聞書信撰寫與編譯)(英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-韓文組"}'::jsonb, NULL)
